// Index by dexId + formName for fast lookup
const POKEDEX = {};
POKEDEX_DATA.forEach(p => {
  const key = p.dexId + (p.formName ? '_' + p.formName.replace(/\s+/g,'_') : '');
  POKEDEX[key] = p;
});

// Lookup by name (base form)
function dexByName(name) {
  return POKEDEX_DATA.find(p => p.name === name && !p.formName) || null;
}

// Get all forms of a dexId
function getForms(dexId) {
  return POKEDEX_DATA.filter(p => p.dexId === dexId);
}

// Get family members
function getFamilyMembers(familyId) {
  const seen = new Set();
  return POKEDEX_DATA.filter(p => {
    if (p.familyId !== familyId || p.formName) return false;
    if (seen.has(p.dexId)) return false;
    seen.add(p.dexId); return true;
  }).sort((a,b) => a.dexId - b.dexId);
}
